// Primary path: LeadSimple REST via the mapping adapter (ADR-4). All CRM
// specifics live in leadsimple-map.json. Retries 3x with 2s/8s/30s backoff,
// 10s timeout per attempt. Requires NODE_FUNCTION_ALLOW_BUILTIN=fs.
const fs = require('fs');
const MAP_PATH = '/home/node/.n8n/wgc/leadsimple-map.json';
const payload = $json.payload;
if (!payload || !payload.submission_id) throw new Error('WF-2 called without a canonical payload');

let map = { enabled: false };
try { map = JSON.parse(fs.readFileSync(MAP_PATH, 'utf8')); } catch (e) { /* adapter absent -> fallback */ }

// LeadSimple parse email (exact v2 template, #14): plain text, one field per
// line, capitalized labels. The parser keys on these labels.
function nv(v) { return v === null || v === undefined ? '' : String(v); }
const emailText = [
  'Name: ' + nv(payload.name),
  'Email: ' + nv(payload.email),
  'Phone: ' + nv(payload.phone),
  'Zip: ' + nv(payload.zip),
  'Square Footage: ' + nv(payload.sqft),
  'Bedrooms: ' + nv(payload.bedrooms),
  'Ebook Requested: ' + (payload.ebook_opt_in ? 'yes' : 'no')
].join('\n');

let deliveredApi = false;
let apiError = '';
if (map.enabled === true && map.url) {
  const crmBody = {};
  for (const [ours, theirs] of Object.entries(map.field_map || {})) {
    const path = ours.split('.');
    let val = payload;
    for (const seg of path) val = val == null ? null : val[seg];
    crmBody[theirs] = val;
  }
  Object.assign(crmBody, map.static_fields || {});
  const headers = { 'Content-Type': 'application/json' };
  if (map.auth_header) headers[map.auth_header] = $env.LEADSIMPLE_API_KEY;
  const backoff = [2000, 8000, 30000];
  for (let attempt = 0; attempt < 3 && !deliveredApi; attempt++) {
    try {
      await this.helpers.httpRequest({ method: 'POST', url: map.url, headers, body: crmBody, json: true, timeout: 10000 });
      deliveredApi = true;
    } catch (e) {
      apiError = String(e.message || e);
      if (attempt < 2) await new Promise(function (r) { setTimeout(r, backoff[attempt]); });
    }
  }
}

return [{ json: {
  delivered_api: deliveredApi,
  api_error: apiError,
  email_text: emailText,
  submission_id: payload.submission_id,
  lead_name: nv(payload.name)
} }];

