// Record which path delivered (feeds WF-3 weekly export, instrument I1).
const fs = require('fs');
const METRICS = '/home/node/.n8n/wgc-metrics.json';
let m = { days: {} };
try { m = JSON.parse(fs.readFileSync(METRICS, 'utf8')); } catch (e) { /* first run */ }
const day = new Date().toISOString().slice(0, 10);
m.days[day] = m.days[day] || { submissions: 0, bots: 0, delivered_api: 0, delivered_email: 0 };
m.days[day][$('CRM API attempt (mapped)').first().json.delivered_api ? 'delivered_api' : 'delivered_email'] += 1;
fs.writeFileSync(METRICS, JSON.stringify(m));
return [{ json: { delivered: true, submission_id: $('CRM API attempt (mapped)').first().json.submission_id } }];
